download.download-software:
				${url}
				${download\-software\-name}
				<#if verify\-enable?has_content && (verify\-enable == true || verify\-enable == false)>
				${verify\-enable}
			</#if>
			<#if key\-name?has_content && mode\-HTTPS == "False" >
			    {key\-name}
			    </#if>
			    <#if mode\-HTTPS == "tls" || mode\-HTTPS == "TLS">
			    <#if server\-public\-key?has_content >
			    ${server\-public\-key}
          			</#if>
         		    </#if>
			    <#if mode\-HTTPS == "mtls" || mode\-HTTPS == "mTLS">
			    <#if mTLS\-with\-EST?has_content && mTLS\-with\-EST == false >
         		    <#if server\-public\-key?has_content >
         		    ${server\-public\-key}
        		</#if>
        		<#if client\-key\-reference?has_content && client\-public\-key\-reference?has_content >

        		    ${client\-key\-reference}
        		    ${client\-public\-key\-reference}

        	    </#if>
        	    </#if>
        	<#if mTLS\-with\-EST?has_content && mTLS\-with\-EST == true >
        	<#if server\-auth\-est\-profile\-name?has_content >
        	${server\-auth\-est\-profile\-name}
         	    </#if>
                 <#if client\-auth\-est\-profile\-name?has_content >
                 ${client\-auth\-est\-profile\-name}
                </#if>
		</#if>
        	</#if>
